Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportwwMonitoraCheques-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CheCreCliCod.IsEmpty() AND &CheCreCliRaz.IsEmpty() AND &CheCreVlrSdo.IsEmpty() AND &CheMot.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheCreCliCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(&CheCreCliRaz) WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 3, "") &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = &CheCreVlrSdo.ToString() If Not &CheMot.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = &CheMot.EnumerationDescription() Endif EndIf
If not (&CheDtaVct.IsEmpty() AND &CheDtaVct_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Vcto.") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &CheDtaVct WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &CheDtaVct_To EndIf
If not (&CheTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "sd") If Not &CheTip.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CheTip.EnumerationDescription() Endif EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CHEVARNRO' &CheVarNro1.FromString(&GridStateDynamicFilter.Value) If not &CheVarNro1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nº Cheque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheVarNro1) EndIf Case &DynamicFiltersSelector1 = !'CHEVLR' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CheVlr1.FromString(&GridStateDynamicFilter.Value) If not &CheVlr1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheVlr1 EndIf Case &DynamicFiltersSelector1 = !'CHETITCPF' &CheTitCpf1.FromString(&GridStateDynamicFilter.Value) If not &CheTitCpf1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit.CPF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitCpf1) EndIf Case &DynamicFiltersSelector1 = !'CHETITNOM' &CheTitNom1.FromString(&GridStateDynamicFilter.Value) If not &CheTitNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit. Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitNom1) EndIf Case &DynamicFiltersSelector1 = !'CHEBANCOD' &CheBanCod1.FromString(&GridStateDynamicFilter.Value) If not &CheBanCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Banco" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheBanCod1) EndIf Case &DynamicFiltersSelector1 = !'CHEAGECOD' &CheAgeCod1.FromString(&GridStateDynamicFilter.Value) If not &CheAgeCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Agência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheAgeCod1 EndIf Case &DynamicFiltersSelector1 = !'CHECON' &CheCon1.FromString(&GridStateDynamicFilter.Value) If not &CheCon1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Conta" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheCon1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CHEVARNRO' &CheVarNro2.FromString(&GridStateDynamicFilter.Value) If not &CheVarNro2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nº Cheque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheVarNro2) EndIf Case &DynamicFiltersSelector2 = !'CHEVLR' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CheVlr2.FromString(&GridStateDynamicFilter.Value) If not &CheVlr2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheVlr2 EndIf Case &DynamicFiltersSelector2 = !'CHETITCPF' &CheTitCpf2.FromString(&GridStateDynamicFilter.Value) If not &CheTitCpf2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit.CPF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitCpf2) EndIf Case &DynamicFiltersSelector2 = !'CHETITNOM' &CheTitNom2.FromString(&GridStateDynamicFilter.Value) If not &CheTitNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit. Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitNom2) EndIf Case &DynamicFiltersSelector2 = !'CHEBANCOD' &CheBanCod2.FromString(&GridStateDynamicFilter.Value) If not &CheBanCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Banco" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheBanCod2) EndIf Case &DynamicFiltersSelector2 = !'CHEAGECOD' &CheAgeCod2.FromString(&GridStateDynamicFilter.Value) If not &CheAgeCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Agência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheAgeCod2 EndIf Case &DynamicFiltersSelector2 = !'CHECON' &CheCon2.FromString(&GridStateDynamicFilter.Value) If not &CheCon2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Conta" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheCon2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CHEVARNRO' &CheVarNro3.FromString(&GridStateDynamicFilter.Value) If not &CheVarNro3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Nº Cheque" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheVarNro3) EndIf Case &DynamicFiltersSelector3 = !'CHEVLR' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CheVlr3.FromString(&GridStateDynamicFilter.Value) If not &CheVlr3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "<") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", "=") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Valor", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheVlr3 EndIf Case &DynamicFiltersSelector3 = !'CHETITCPF' &CheTitCpf3.FromString(&GridStateDynamicFilter.Value) If not &CheTitCpf3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit.CPF" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitCpf3) EndIf Case &DynamicFiltersSelector3 = !'CHETITNOM' &CheTitNom3.FromString(&GridStateDynamicFilter.Value) If not &CheTitNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tit. Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheTitNom3) EndIf Case &DynamicFiltersSelector3 = !'CHEBANCOD' &CheBanCod3.FromString(&GridStateDynamicFilter.Value) If not &CheBanCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Banco" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheBanCod3) EndIf Case &DynamicFiltersSelector3 = !'CHEAGECOD' &CheAgeCod3.FromString(&GridStateDynamicFilter.Value) If not &CheAgeCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Agência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CheAgeCod3 EndIf Case &DynamicFiltersSelector3 = !'CHECON' &CheCon3.FromString(&GridStateDynamicFilter.Value) If not &CheCon3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Conta" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CheCon3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Responsável" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = 'Banco"AG"C.C.DIG' &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Nro" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Valor" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Saldo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Motivo " &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Vcto." &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Títular"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CheDtaVct when &OrderedBy = 1 order EmpCod (CheDtaVct) when &OrderedBy = 2 order CheVarNro when &OrderedBy = 3 AND &OrderedDsc = False order (CheVarNro) when &OrderedBy = 3 AND &OrderedDsc = True order CheVlr when &OrderedBy = 4 AND &OrderedDsc = False order (CheVlr) when &OrderedBy = 4 AND &OrderedDsc = True order CheMot when &OrderedBy = 5 AND &OrderedDsc = False order (CheMot) when &OrderedBy = 5 AND &OrderedDsc = True order CheDtaEmi when &OrderedBy = 6 AND &OrderedDsc = False order (CheDtaEmi) when &OrderedBy = 6 AND &OrderedDsc = True order CheDtaVct when &OrderedBy = 7 AND &OrderedDsc = False order (CheDtaVct) when &OrderedBy = 7 AND &OrderedDsc = True
using DSwwMonitoraCheques(&CheCreCliCod, &CheCreCliRaz, &CheCreVlrSdo, &CheMot, &CheDtaVct, &CheDtaVct_To , &CheTip, &DynamicFiltersSelector1, &DynamicFiltersOperator1, &CheVarNro1, &CheVlr1, &CheTitCpf1 , &CheTitNom1, &CheBanCod1, &CheAgeCod1, &CheCon1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &DynamicFiltersOperator2, &CheVarNro2, &CheVlr2, &CheTitCpf2, &CheTitNom2, &CheBanCod2 , &CheAgeCod2, &CheCon2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CheVarNro3 , &CheVlr3, &CheTitCpf3, &CheTitNom3, &CheBanCod3, &CheAgeCod3, &CheCon3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' if CheCreCliCodRaz.Length() > 20 &CheCreCliCodRaz = substr(CheCreCliCodRaz, 1, 20) + '...' Else &CheCreCliCodRaz = CheCreCliCodRaz Endif
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = WWP_Export_SecureText(&CheCreCliCodRaz) &BancoAgenciaConta = 'B:'+trim(CheBanCod) + ' AG:' + trim(str(CheAgeCod)) + ' C.C:'+ trim(CheCon) &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&BancoAgenciaConta) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(CheVarNro) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Number = CheVlr &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Number = CheCreVlrSdo &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = CheMot.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Date = CheDtaEmi &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Date = CheDtaVct if CheTitNom.Length() > 20 &gridCheTitNom = substr(CheTitNom, 1, 20) + '...' Else &gridCheTitNom = CheTitNom Endif
&ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(&gridCheTitNom)
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwMonitoraChequesGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwMonitoraChequesGridState")) Else &GridState.FromXml(&Session.Get(!"wwMonitoraChequesGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CHECRECLICOD" &CheCreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CHECRECLIRAZ" &CheCreCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CHECREVLRSDO" &CheCreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CHEMOT" &CheMot.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CHEDTAVCT" &CheDtaVct.FromString(&GridStateFilterValue.Value) &CheDtaVct_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"CHETIP" &CheTip.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
